import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication and Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/Safety/authentication-and-login-devices.md","filePath":"en/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),l={name:"en/Safety/authentication-and-login-devices.md"};function r(c,e,h,u,p,g){return o(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="authentication-and-login-device-management" tabindex="-1">Authentication and Login Device Management <a class="header-anchor" href="#authentication-and-login-device-management" aria-label="Permalink to &quot;Authentication and Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> and <code>Login Device Management</code> protect your ImgBed admin panel, public upload entry, and WebDAV access.</p><p>Use this page to set access credentials, review signed-in devices, and revoke old sessions when needed.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open the admin panel, then go to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>The page contains two main areas:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="what-authentication-management-does" tabindex="-1">What Authentication Management Does <a class="header-anchor" href="#what-authentication-management-does" aria-label="Permalink to &quot;What Authentication Management Does&quot;">​</a></h2><p>Authentication Management stores access credentials.</p><p>There are two types:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication is the upload password.</p><p>After an upload password is set, regular visitors must enter it before using the upload page. This is useful when you do not want the public upload page to be open to everyone.</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="setting-the-upload-password" tabindex="-1">Setting the Upload Password <a class="header-anchor" href="#setting-the-upload-password" aria-label="Permalink to &quot;Setting the Upload Password&quot;">​</a></h3><p>When an upload password is configured:</p><ul><li>Visitors must enter the password before using the upload page.</li><li>Uploading is available only after the password is accepted.</li><li>If user-side device sessions are enabled, ImgBed records that user-side device.</li></ul><p>Changing the upload password invalidates old user-side sessions. Visitors need to enter the new password again.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication uses an admin username and password.</p><p>This protects the admin panel. For production use, you should always configure it.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="setting-admin-credentials" tabindex="-1">Setting Admin Credentials <a class="header-anchor" href="#setting-admin-credentials" aria-label="Permalink to &quot;Setting Admin Credentials&quot;">​</a></h3><p>When an admin username and password are configured:</p><ul><li>Opening the admin panel requires login.</li><li>Successful login creates an admin device record.</li><li>You can review, clean up, or force devices offline in Login Device Management.</li></ul><p>Changing the admin username or password invalidates old admin sessions. You need to sign in again.</p><h2 id="what-login-device-management-does" tabindex="-1">What Login Device Management Does <a class="header-anchor" href="#what-login-device-management-does" aria-label="Permalink to &quot;What Login Device Management Does&quot;">​</a></h2><p>Login Device Management shows devices that have signed in.</p><p>It helps you check:</p><ul><li>Which devices have accessed the admin panel.</li><li>Which devices have accessed the user-side upload page.</li><li>Which WebDAV clients have connected.</li><li>Whether a device session is still valid.</li><li>Whether old devices should be forced offline.</li></ul><p>The page has three tabs:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>At the top of Login Device Management, you can configure global cookie behavior.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Controls how many days a user-side login can stay active.</p><p>For example, if you set it to 14 days, visitors usually do not need to enter the upload password again within 14 days.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Controls how many days an admin login can stay active.</p><p>For example, if you set it to 14 days, administrators usually do not need to sign in again within 14 days.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>When Secure mode is enabled, browsers only send login cookies over HTTPS.</p><p>Enable it for production HTTPS sites. Do not enable it for local HTTP testing, or you may see &quot;login succeeded, but refresh logs me out&quot; behavior.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>The Admin tab shows devices that signed in to the admin panel.</p><p>Device records appear only after admin credentials are configured and the admin panel is accessed through login.</p><p>Each device card can show:</p><ul><li>Device and browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>If you see an unfamiliar device, use <code>Force Offline</code> to invalidate it.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> removes old login records in the current tab in bulk.</p><p>Use it when you suspect old sessions may still be active on other devices.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> invalidates one device session.</p><p>After a device is forced offline:</p><ul><li>Admin devices must sign in again.</li><li>User-side devices must enter the upload password again.</li><li>WebDAV clients must authenticate again.</li></ul><p>Expired or invalid devices can also be removed.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>The current device card is marked as <code>Current Device</code>.</p><p>After signing out the current device:</p><ul><li>The current admin session is signed out.</li><li>The current user-side session is signed out.</li></ul><p>You need to sign in again before continuing to use that area.</p>',65)])])}const b=t(l,[["render",r]]);export{f as __pageData,b as default};
